// src/wishlists/wishlists.service.ts
async addProduct(userId: string, productId: string): Promise<Wishlist> {
    const wishlist = await this.findOrCreateByUser(userId);
    const product = await this.productService.findOne(productId);

    // Vérifier si le produit n'est pas déjà dans la wishlist
    const alreadyExists = wishlist.products.some(p => p.id === productId);
    if (alreadyExists) {
        throw new ConflictException('Produit déjà dans la wishlist');
    }

    wishlist.products.push(product);
    return this.wishlistRepository.save(wishlist);
}

async removeProduct(userId: string, productId: string): Promise<Wishlist> {
    const wishlist = await this.findByUser(userId);
    if (!wishlist) throw new NotFoundException('Wishlist non trouvée');

    wishlist.products = wishlist.products.filter(p => p.id !== productId);
    return this.wishlistRepository.save(wishlist);
}

async clearWishlist(userId: string): Promise<void> {
    const wishlist = await this.findByUser(userId);
    if (wishlist) {
        wishlist.products = [];
        await this.wishlistRepository.save(wishlist);
    }
}
