async enablePublicSharing(userId: string): Promise<{ shareToken: string; shareUrl: string }> {
    const wishlist = await this.findOrCreateByUser(userId);

    if (!wishlist.isPublic || !wishlist.shareToken) {
        wishlist.isPublic = true;
        wishlist.shareToken = crypto.randomBytes(32).toString('hex');
        await this.wishlistRepository.save(wishlist);
    }

    const shareUrl = `${this.configService.get('APP_URL')}/wishlists/public/${wishlist.shareToken}`;
    return { shareToken: wishlist.shareToken, shareUrl };
}

async getPublicWishlist(token: string) {
    const wishlist = await this.wishlistRepository.findOne({
        where: { shareToken: token, isPublic: true },
        relations: ['user', 'products']
    });

    if (!wishlist) {
        throw new NotFoundException('Wishlist publique non trouvée ou non partagée');
    }

    // Ne retourner que les champs publics
    return {
        name: wishlist.name,
        ownerName: `${wishlist.user.firstName} ${wishlist.user.lastName}`,
        products: wishlist.products.map(p => ({
            id: p.id,
            name: p.name,
            price: p.price,
            mainImage: p.images?.[0],
            averageRating: p.averageRating
        })),
        createdAt: wishlist.createdAt
    };
}
