async updateStock(productId: string, newStock: number) {
    const oldProduct = await this.findOne(productId);
    const updated = await this.productRepository.update(productId, { stock: newStock });

    // Si le stock passe de 0 à >0
    if (oldProduct.stock === 0 && newStock > 0) {
        await this.notificationQueue.add('stock-restored', {
            productId,
            productName: oldProduct.name
        });
    }

    return updated;
