// wishlists.service.ts
async addMultipleProducts(userId: string, productIds: string[]): Promise<Wishlist> {
    const wishlist = await this.findOrCreateByUser(userId);

    // Récupérer les produits existants dans la wishlist
    const existingProductIds = new Set(wishlist.products.map(p => p.id));

    // Filtrer les nouveaux produits (non déjà présents)
    const newProductIds = productIds.filter(id => !existingProductIds.has(id));

    if (newProductIds.length === 0) {
        return wishlist;
    }

    // Récupérer les entités Product
    const newProducts = await this.productRepository.findByIds(newProductIds);

    wishlist.products.push(...newProducts);
    return this.wishlistRepository.save(wishlist);
}
